package com.weeklycommit.ai.experiment;

/**
 * Immutable result of an experiment variant assignment.
 *
 * @param experimentName
 *            the experiment key (e.g. {@code "llm-model"})
 * @param variant
 *            {@code "control"} or {@code "treatment"}
 * @param value
 *            the resolved config value for the assigned variant
 */
public record ExperimentAssignment(String experimentName, String variant, String value) {

	/** Returns {@code true} if the treatment arm was assigned. */
	public boolean isTreatment() {
		return ExperimentService.VARIANT_TREATMENT.equals(variant);
	}

	/** Returns {@code true} if the control arm was assigned. */
	public boolean isControl() {
		return ExperimentService.VARIANT_CONTROL.equals(variant);
	}
}

package com.weeklycommit.ai.experiment;

import java.util.ArrayList;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import org.springframework.boot.context.properties.ConfigurationProperties;
import org.springframework.context.annotation.Configuration;

/**
 * Configuration properties for AI pipeline A/B experiments.
 *
 * <p>
 * Loaded from the {@code ai.experiments} prefix in {@code application.yml}.
 * Each entry in the {@code experiments} map is keyed by experiment name (e.g.
 * {@code llm-model}) and carries the full variant definition.
 *
 * <p>
 * All experiments default to {@code enabled: false} and
 * {@code controlWeight: 1.0}, so existing behaviour is unchanged unless an
 * experiment is explicitly enabled with a lower control weight.
 */
@Configuration
@ConfigurationProperties(prefix = "ai.experiments")
public class ExperimentConfig {

	private Map<String, ExperimentDefinition> experiments = new LinkedHashMap<>();

	public Map<String, ExperimentDefinition> getExperiments() {
		return experiments;
	}

	public void setExperiments(Map<String, ExperimentDefinition> experiments) {
		this.experiments = experiments;
	}

	/**
	 * Defines a single experiment's variant configuration.
	 *
	 * <p>
	 * Mutable plain bean so that Spring's {@code @ConfigurationProperties} binding
	 * can populate it via setters.
	 */
	public static class ExperimentDefinition {

		/** Whether the experiment is active. Defaults to {@code false}. */
		private boolean enabled = false;

		/**
		 * Fraction of traffic that receives the control variant (0.0–1.0). Defaults to
		 * {@code 1.0} (100 % control).
		 */
		private double controlWeight = 1.0;

		/** Value returned when the control arm is selected. */
		private String controlValue;

		/** Value returned when the treatment arm is selected. */
		private String treatmentValue;

		/**
		 * Optional list of suggestion types (e.g. {@code RAG_QUERY}) for which this
		 * experiment is applicable. Empty list means it applies to all contexts.
		 */
		private List<String> appliesTo = new ArrayList<>();

		public boolean isEnabled() {
			return enabled;
		}

		public void setEnabled(boolean enabled) {
			this.enabled = enabled;
		}

		public double getControlWeight() {
			return controlWeight;
		}

		public void setControlWeight(double controlWeight) {
			this.controlWeight = controlWeight;
		}

		public String getControlValue() {
			return controlValue;
		}

		public void setControlValue(String controlValue) {
			this.controlValue = controlValue;
		}

		public String getTreatmentValue() {
			return treatmentValue;
		}

		public void setTreatmentValue(String treatmentValue) {
			this.treatmentValue = treatmentValue;
		}

		public List<String> getAppliesTo() {
			return appliesTo;
		}

		public void setAppliesTo(List<String> appliesTo) {
			this.appliesTo = appliesTo;
		}
	}
}

package com.weeklycommit.ai.experiment;

import java.util.LinkedHashMap;
import java.util.Map;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

/**
 * Lightweight A/B experiment assignment service.
 *
 * <p>
 * Variant assignment follows this priority order:
 * <ol>
 * <li>Environment-variable override:
 * {@code AB_FORCE_<EXPERIMENT_NAME_UPPER>=control|treatment} (useful for
 * testing and canary deploys).</li>
 * <li>Random draw: assigns control if {@code Math.random() < controlWeight},
 * otherwise treatment.</li>
 * </ol>
 *
 * <p>
 * All experiments default to disabled and {@code controlWeight=1.0}, so
 * behaviour is unchanged unless an experiment is explicitly enabled.
 */
@Service
public class ExperimentService {

	private static final Logger log = LoggerFactory.getLogger(ExperimentService.class);

	static final String VARIANT_CONTROL = "control";
	static final String VARIANT_TREATMENT = "treatment";

	private final ExperimentConfig config;

	public ExperimentService(ExperimentConfig config) {
		this.config = config;
	}

	// ── Public API ───────────────────────────────────────────────────────

	/**
	 * Returns whether the named experiment is configured and enabled.
	 *
	 * @param experimentName
	 *            the experiment key (e.g. {@code "llm-model"})
	 */
	public boolean isEnabled(String experimentName) {
		ExperimentConfig.ExperimentDefinition def = config.getExperiments().get(experimentName);
		return def != null && def.isEnabled();
	}

	/**
	 * Assigns a variant for the given experiment and user, returning the full
	 * {@link ExperimentAssignment}.
	 *
	 * <p>
	 * If the experiment is disabled or not found, returns a control assignment with
	 * a {@code null} value so callers can safely use
	 * {@link ExperimentAssignment#value()} without null-checks breaking the
	 * disabled-default contract.
	 *
	 * @param experimentName
	 *            the experiment key
	 * @param userId
	 *            opaque caller identity used for deterministic overrides (env-var
	 *            path ignores this)
	 */
	public ExperimentAssignment assign(String experimentName, String userId) {
		ExperimentConfig.ExperimentDefinition def = config.getExperiments().get(experimentName);

		if (def == null || !def.isEnabled()) {
			return new ExperimentAssignment(experimentName, VARIANT_CONTROL,
					def != null ? def.getControlValue() : null);
		}

		String forced = readForceOverride(experimentName);
		if (forced != null) {
			String value = VARIANT_TREATMENT.equals(forced) ? def.getTreatmentValue() : def.getControlValue();
			log.debug("Experiment '{}' forced to variant='{}' via env override", experimentName, forced);
			return new ExperimentAssignment(experimentName, forced, value);
		}

		String variant = (Math.random() < def.getControlWeight()) ? VARIANT_CONTROL : VARIANT_TREATMENT;
		String value = VARIANT_TREATMENT.equals(variant) ? def.getTreatmentValue() : def.getControlValue();
		log.debug("Experiment '{}' assigned variant='{}' for userId='{}'", experimentName, variant, userId);
		return new ExperimentAssignment(experimentName, variant, value);
	}

	/**
	 * Convenience method returning just the resolved value string.
	 *
	 * @param experimentName
	 *            the experiment key
	 * @param userId
	 *            opaque caller identity
	 * @return the control or treatment value, or {@code null} if the experiment is
	 *         not found
	 */
	public String resolveValue(String experimentName, String userId) {
		return assign(experimentName, userId).value();
	}

	/**
	 * Returns a snapshot of assignments for all <em>enabled</em> experiments for
	 * the given user. The map key is the experiment name; value is the
	 * {@link ExperimentAssignment}.
	 *
	 * @param userId
	 *            opaque caller identity
	 */
	public Map<String, ExperimentAssignment> getActiveAssignments(String userId) {
		Map<String, ExperimentAssignment> result = new LinkedHashMap<>();
		for (String name : config.getExperiments().keySet()) {
			if (isEnabled(name)) {
				result.put(name, assign(name, userId));
			}
		}
		return result;
	}

	// ── Internal helpers ─────────────────────────────────────────────────

	/**
	 * Reads an environment-variable force-override for the experiment.
	 *
	 * <p>
	 * Variable name: {@code AB_FORCE_<EXPERIMENT_NAME_UPPER>} where hyphens are
	 * replaced with underscores, e.g. {@code AB_FORCE_LLM_MODEL}.
	 *
	 * @return {@code "control"}, {@code "treatment"}, or {@code null} if not set
	 */
	String readForceOverride(String experimentName) {
		String envKey = "AB_FORCE_" + experimentName.toUpperCase().replace('-', '_');
		String raw = System.getenv(envKey);
		if (raw == null) {
			return null;
		}
		String normalised = raw.trim().toLowerCase();
		if (VARIANT_CONTROL.equals(normalised) || VARIANT_TREATMENT.equals(normalised)) {
			return normalised;
		}
		log.warn("Ignoring unrecognised AB_FORCE value '{}' for experiment '{}'", raw, experimentName);
		return null;
	}
}

package com.weeklycommit.ai.experiment;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.Mockito.doReturn;
import static org.mockito.Mockito.spy;

import java.util.List;
import java.util.Map;
import org.junit.jupiter.api.Test;

/**
 * Unit tests for {@link ExperimentService}.
 *
 * <p>
 * Tests use a hand-built {@link ExperimentConfig} rather than Spring context so
 * they run fast with no I/O. The env-var path is tested by spying on
 * {@code readForceOverride}.
 */
class ExperimentServiceTest {

	// ── Helpers ──────────────────────────────────────────────────────────

	private static ExperimentConfig.ExperimentDefinition def(boolean enabled, double controlWeight, String control,
			String treatment, List<String> appliesTo) {
		ExperimentConfig.ExperimentDefinition d = new ExperimentConfig.ExperimentDefinition();
		d.setEnabled(enabled);
		d.setControlWeight(controlWeight);
		d.setControlValue(control);
		d.setTreatmentValue(treatment);
		d.setAppliesTo(appliesTo);
		return d;
	}

	private static ExperimentConfig configWith(Map<String, ExperimentConfig.ExperimentDefinition> entries) {
		ExperimentConfig cfg = new ExperimentConfig();
		cfg.setExperiments(entries);
		return cfg;
	}

	private static ExperimentService service(ExperimentConfig cfg) {
		return new ExperimentService(cfg);
	}

	// ── isEnabled ────────────────────────────────────────────────────────

	@Test
	void isEnabled_disabledExperiment_returnsFalse() {
		ExperimentConfig cfg = configWith(
				Map.of("llm-model", def(false, 1.0, "control-llm", "treatment-llm", List.of())));
		assertThat(service(cfg).isEnabled("llm-model")).isFalse();
	}

	@Test
	void isEnabled_nonExistentExperiment_returnsFalse() {
		ExperimentConfig cfg = configWith(Map.of());
		assertThat(service(cfg).isEnabled("does-not-exist")).isFalse();
	}

	@Test
	void isEnabled_enabledExperiment_returnsTrue() {
		ExperimentConfig cfg = configWith(Map.of("hyde", def(true, 1.0, "disabled", "enabled", List.of("RAG_QUERY"))));
		assertThat(service(cfg).isEnabled("hyde")).isTrue();
	}

	// ── assign: disabled experiment ──────────────────────────────────────

	@Test
	void assign_disabledExperiment_returnsControl() {
		ExperimentConfig cfg = configWith(
				Map.of("llm-model", def(false, 0.0, "control-llm", "treatment-llm", List.of())));
		ExperimentAssignment assignment = service(cfg).assign("llm-model", "user-1");
		assertThat(assignment.variant()).isEqualTo("control");
		assertThat(assignment.value()).isEqualTo("control-llm");
		assertThat(assignment.isControl()).isTrue();
		assertThat(assignment.isTreatment()).isFalse();
	}

	@Test
	void assign_unknownExperiment_returnsControlWithNullValue() {
		ExperimentConfig cfg = configWith(Map.of());
		ExperimentAssignment assignment = service(cfg).assign("unknown", "user-1");
		assertThat(assignment.variant()).isEqualTo("control");
		assertThat(assignment.value()).isNull();
	}

	// ── assign: controlWeight=1.0 always returns control ─────────────────

	@Test
	void assign_enabledWithControlWeight1_alwaysReturnsControl() {
		ExperimentConfig cfg = configWith(
				Map.of("llm-model", def(true, 1.0, "control-llm", "treatment-llm", List.of())));
		ExperimentService svc = service(cfg);
		// Run many times — controlWeight=1.0 must always land on control
		for (int i = 0; i < 200; i++) {
			ExperimentAssignment a = svc.assign("llm-model", "user-" + i);
			assertThat(a.variant()).as("iteration %d should be control", i).isEqualTo("control");
		}
	}

	// ── assign: controlWeight=0.0 always returns treatment ───────────────

	@Test
	void assign_enabledWithControlWeight0_alwaysReturnsTreatment() {
		ExperimentConfig cfg = configWith(
				Map.of("llm-model", def(true, 0.0, "control-llm", "treatment-llm", List.of())));
		ExperimentService svc = service(cfg);
		for (int i = 0; i < 200; i++) {
			ExperimentAssignment a = svc.assign("llm-model", "user-" + i);
			assertThat(a.variant()).as("iteration %d should be treatment", i).isEqualTo("treatment");
			assertThat(a.value()).isEqualTo("treatment-llm");
		}
	}

	// ── resolveValue ─────────────────────────────────────────────────────

	@Test
	void resolveValue_disabledExperiment_returnsControlValue() {
		ExperimentConfig cfg = configWith(Map.of("hyde", def(false, 1.0, "disabled", "enabled", List.of())));
		assertThat(service(cfg).resolveValue("hyde", "u1")).isEqualTo("disabled");
	}

	// ── env-var override ─────────────────────────────────────────────────

	@Test
	void assign_envVarForcesControl_returnsControlEvenWithControlWeight0() {
		ExperimentConfig cfg = configWith(Map.of("llm-model", def(true, 0.0, "ctrl-val", "treat-val", List.of())));
		ExperimentService svc = spy(service(cfg));
		doReturn("control").when(svc).readForceOverride("llm-model");

		ExperimentAssignment a = svc.assign("llm-model", "u1");
		assertThat(a.variant()).isEqualTo("control");
		assertThat(a.value()).isEqualTo("ctrl-val");
	}

	@Test
	void assign_envVarForcesTreatment_returnsTreatmentEvenWithControlWeight1() {
		ExperimentConfig cfg = configWith(Map.of("llm-model", def(true, 1.0, "ctrl-val", "treat-val", List.of())));
		ExperimentService svc = spy(service(cfg));
		doReturn("treatment").when(svc).readForceOverride("llm-model");

		ExperimentAssignment a = svc.assign("llm-model", "u1");
		assertThat(a.variant()).isEqualTo("treatment");
		assertThat(a.value()).isEqualTo("treat-val");
	}

	// ── getActiveAssignments ─────────────────────────────────────────────

	@Test
	void getActiveAssignments_onlyIncludesEnabledExperiments() {
		ExperimentConfig cfg = configWith(Map.of("llm-model", def(true, 1.0, "ctrl-llm", "treat-llm", List.of()),
				"hyde", def(false, 1.0, "disabled", "enabled", List.of("RAG_QUERY")), "embedding-model",
				def(false, 1.0, "small", "large", List.of())));
		Map<String, ExperimentAssignment> active = service(cfg).getActiveAssignments("u1");
		assertThat(active).containsOnlyKeys("llm-model");
		assertThat(active.get("llm-model").variant()).isEqualTo("control");
